                                    </div>
                                    <!-- <div class="result-actions" v-if="result.type === 'Invoice' || result.type === 'Talygen_bill'">
                                        <a 
                                            href="javascript:;" 
                                            class="action-btn attach-btn" 
                                            title="Attach"
                                            @click.stop="handleAttach(result)"
                                        >
                                            <em class="fa fa-paperclip"></em>
                                        </a>
                                        <button 
                                            class="btn btn-sm btn-primary summarize-btn"
                                            @click.stop="handleSummarize(result)"
                                        >
                                            Summarize
                                        </button>
                                    </div> -->
                                </div>
                            </div>

                            <!-- No Results -->
                            <div v-else-if="!isLoading" class="text-center p-5">
                                <em class="fa fa-search fa-3x text-muted mb-3"></em>
                                <p class="text-muted">{{ $t('NoResultsFound') || 'No results found' }}</p>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <!-- Pagination -->
            <div class="row mt-4" v-if="totalPages > 0">
                <div class="col-12">
                    <div class="nu-paging">
                        <nav aria-label="Page navigation example col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left">
                            <ul class="pagination row">
                                <li class="col-sm-12 col-md-6 col-lg-6 col-xl-6 float-left choose-page">
                                    <span class="mr-2">Show</span>
                                    <span class="select">
                                        <select class="form-control form-control-sm" @change="onPageSizeChange" id="pageSize" name="pageSize" v-model="pageSize">
                                            <option v-for="(item, itemIndex) in pageSizeOptions" :value="item" :key="itemIndex">{{ item }}</option>
                                        </select>
                                    </span>
                                    <span class="ml-2">
                                        Showing {{ ((currentPage - 1) * pageSize) + 1 }} to {{ Math.min(currentPage * pageSize, totalCount) }} of {{ totalCount }} entries
                                    </span>
                                </li>
                                <li class="col-sm-12 col-md-6 col-lg-6 col-xl-6 float-left">
                                    <ul class="paging-count" v-if="totalPages > 1">
                                        <li class="page-item">
                                            <a v-if="currentPage != 1" href="javascript:;" class="page-link first" @click.prevent="goToPage(1)" title="First">First</a>
                                            <a v-if="currentPage == 1" class="page-link first disabled" title="First">First</a>
                                        </li>
                                        <li class="page-item">
                                            <a v-if="currentPage != 1" class="page-link previous" href="javascript:;" @click.prevent="goToPage(currentPage - 1)" title="Previous">Previous</a>
                                            <a v-if="currentPage == 1" class="page-link previous disabled" title="Previous">Previous</a>
                                        </li>
                                        <li 
                                            v-for="page in visiblePages" 
                                            :key="page"
                                            class="page-item"
                                        >
                                            <a v-if="page == currentPage" class="page-link active" href="javascript:;">{{ page }}</a>
                                            <a v-if="page != currentPage" href="javascript:;" class="page-link" @click.prevent="goToPage(page)">{{ page }}</a>
                                        </li>
                                        <li class="page-item">
                                            <a v-if="currentPage < totalPages" class="page-link next" href="javascript:;" @click.prevent="goToPage(currentPage + 1)" title="Next">Next</a>
                                            <a v-if="currentPage >= totalPages" class="page-link disabled next" title="Next">Next</a>
                                        </li>
                                        <li class="page-item">
                                            <a v-if="currentPage != totalPages" href="javascript:;" class="page-link next" @click.prevent="goToPage(totalPages)" title="Last">Last</a>
                                            <a v-if="currentPage == totalPages" class="page-link next disabled" title="Last">Last</a>
                                        </li>
                                    </ul>
                                </li>
                            </ul>
                        </nav>
                    </div>
                </div>
